#define MAX_ARGS 10
#define REC_LENGTH 49
#define REC_WINDOW 10
#define LATITUDE_POS 28
#define OPEN 10000.0f

struct neighbor {
    char entry[REC_LENGTH];
    float dist;
};

// Minimal float parser for OpenCL
// Assumes string contains a valid float representation
static float cl_atof(const char *s) {
    float val = 0.0f;
    float frac = 0.0f;
    float div = 1.0f;
    int sign = 1;
    int i = 0;

    // Skip leading spaces if any (though our data shouldn't have them at the start of the substring)
    while(s[i] == ' ') i++;

    if (s[i] == '-') {
        sign = -1;
        i++;
    }

    // Integer part
    while (s[i] >= '0' && s[i] <= '9') {
        val = val * 10.0f + (s[i] - '0');
        i++;
    }

    // Fractional part
    if (s[i] == '.') {
        i++;
        while (s[i] >= '0' && s[i] <= '9') {
            div *= 10.0f;
            frac += (s[i] - '0') / div;
            i++;
        }
    }

    return sign * (val + frac);
}

__kernel void compute_distances(
    const char *sandbox,
    float *z,
    int rec_count,
    float target_lat,
    float target_long)
{
    int i = get_global_id(0);
    if (i >= rec_count) return;

    // Calculate offset exactly as in the C code:
    // rec_iter = sandbox + (i * REC_LENGTH + LATITUDE_POS - 1);
    // LATITUDE_POS is 28, so offset is i*49 + 27
    int base_offset = i * REC_LENGTH;
    int lat_offset = base_offset + (LATITUDE_POS - 1);

    // Extract latitude and longitude using the helper
    // The original code does: atof(rec_iter) and atof(rec_iter+5)
    float tmp_lat = cl_atof(sandbox + lat_offset);
    float tmp_long = cl_atof(sandbox + lat_offset + 5);

    float dlat = tmp_lat - target_lat;
    float dlon = tmp_long - target_long;

    z[i] = sqrt(dlat * dlat + dlon * dlon);
}

__kernel void update_neighbors(
    const char *sandbox,
    const float *z,
    struct neighbor *neighbors,
    int rec_count,
    int k)
{
    int i = get_global_id(0);
    if (i >= rec_count) return;

    float current_dist = z[i];

    // Find the neighbor with the maximum distance
    float max_dist = -1.0f;
    int max_idx = 0;

    for (int j = 0; j < k; j++) {
        if (neighbors[j].dist > max_dist) {
            max_dist = neighbors[j].dist;
            max_idx = j;
        }
    }

    // If current record is closer than the worst in the list, replace it
    if (current_dist < max_dist) {
        // Copy string
        for (int c = 0; c < REC_LENGTH - 1; c++) {
            char ch = sandbox[i * REC_LENGTH + c];
            neighbors[max_idx].entry[c] = ch;
            if (ch == '\0') break;
        }
        neighbors[max_idx].entry[REC_LENGTH - 1] = '\0';
        neighbors[max_idx].dist = current_dist;
    }
}
